// mm/src/api/downloadDocuments.js
import axios from 'axios';
import { withAuthRetry } from './refresh';
import { getAccessToken } from '../utils/auth';

const API_BASE =
  process.env.REACT_APP_API_BASE_URL || 'https://manuscriptmagic.fowkes.xyz/services';

/** -----------------------------
 * Filename / extension helpers
 * ---------------------------- */

function extFromContentType(ct = '') {
  const t = String(ct).toLowerCase();
  if (t.includes('pdf')) return '.pdf';
  if (t.includes('msword')) return '.doc';
  if (t.includes('officedocument.wordprocessingml')) return '.docx';
  if (t.includes('text/plain')) return '.txt';
  if (t.includes('text/markdown')) return '.md';
  if (t.includes('application/zip')) return '.zip';
  return '';
}

function extFromFilename(name = '') {
  const n = String(name || '').trim();
  const m = n.match(/(\.[a-z0-9]{1,6})$/i);
  return m ? m[1].toLowerCase() : '';
}

function ensureExtension(filename, contentType, fallbackExt = '') {
  const name = String(filename || '').trim();
  if (!name) return `document${fallbackExt || extFromContentType(contentType) || ''}`;
  if (/\.[a-z0-9]{1,6}$/i.test(name)) return name;
  const ext = fallbackExt || extFromContentType(contentType) || '';
  return `${name}${ext}`;
}

function getFilenameFromContentDisposition(cd = '') {
  const v = String(cd || '');
  if (!v) return '';

  const mStar = v.match(/filename\*\s*=\s*([^;]+)/i);
  if (mStar) {
    const raw = mStar[1].trim().replace(/^UTF-8''/i, '').replace(/^"|"$/g, '');
    try {
      return decodeURIComponent(raw);
    } catch {
      return raw;
    }
  }

  const m = v.match(/filename\s*=\s*([^;]+)/i);
  if (m) return m[1].trim().replace(/^"|"$/g, '');

  return '';
}

/** -----------------------------
 * Byte / sniff / debug helpers
 * ---------------------------- */

function toHex(u8, max = 32) {
  return Array.from(u8.slice(0, max))
    .map((b) => b.toString(16).padStart(2, '0'))
    .join(' ');
}

function toAsciiPreview(u8, max = 80) {
  return Array.from(u8.slice(0, max))
    .map((b) => (b >= 32 && b <= 126 ? String.fromCharCode(b) : '.'))
    .join('');
}

function isPdfBytes(u8) {
  // %PDF
  return u8.length >= 4 && u8[0] === 0x25 && u8[1] === 0x50 && u8[2] === 0x44 && u8[3] === 0x46;
}

function isZipBytes(u8) {
  // PK\x03\x04
  return u8.length >= 4 && u8[0] === 0x50 && u8[1] === 0x4b && u8[2] === 0x03 && u8[3] === 0x04;
}

function looksLikeBase64(text) {
  const s = String(text || '').trim();
  if (!s) return false;
  // Allow newlines in base64 output
  const compact = s.replace(/\s+/g, '');
  if (compact.length < 64) return false;
  if (compact.length % 4 !== 0) return false;
  return /^[A-Za-z0-9+/=]+$/.test(compact);
}

function base64ToBytes(b64) {
  const compact = String(b64 || '').replace(/\s+/g, '');
  const bin = atob(compact);
  const u8 = new Uint8Array(bin.length);
  for (let i = 0; i < bin.length; i++) u8[i] = bin.charCodeAt(i);
  return u8;
}

async function blobHeadBytes(blob, n = 128) {
  const buf = await blob.slice(0, n).arrayBuffer();
  return new Uint8Array(buf);
}

async function blobToText(blob) {
  if (typeof blob.text === 'function') return blob.text();
  return new Promise((resolve, reject) => {
    const r = new FileReader();
    r.onload = () => resolve(String(r.result || ''));
    r.onerror = () => reject(new Error('Failed to read blob as text'));
    r.readAsText(blob);
  });
}

/** -----------------------------
 * API call
 * ---------------------------- */

export async function downloadDocument(documentId) {
  if (!documentId) throw new Error('documentId is required');

  if (!process.env.REACT_APP_API_BASE_URL) {
    const blob = new Blob([`Mock file for ${documentId}`], { type: 'text/plain' });
    return { data: blob, headers: { 'content-type': 'text/plain' } };
  }

  const url = `${API_BASE}/downloadDocument.php`;

  return withAuthRetry(async () => {
    const accessToken = await getAccessToken();
    if (!accessToken) throw new Error('Missing access token');

    return axios.post(
      url,
      { documentId, accessToken },
      {
        responseType: 'blob', // keep blob
        headers: {
          Authorization: `Bearer ${accessToken}`,
          'Content-Type': 'application/json',
          Accept: '*/*',
        },
        params: { accessToken },
        validateStatus: (s) => s >= 200 && s < 300,
      }
    );
  });
}

/** -----------------------------
 * Main: download + validate + base64-fix
 * ---------------------------- */

export async function downloadAndSaveDocuments(documentId, filenameFromList) {
  const resp = await downloadDocument(documentId);
  const blob = resp?.data;

  if (!(blob instanceof Blob)) {
    throw new Error('Download failed: response is not a Blob.');
  }

  const headers = resp?.headers || {};
  const contentType = headers['content-type'] || headers['Content-Type'] || blob.type || '';
  const contentDisposition = headers['content-disposition'] || headers['Content-Disposition'] || '';
  const serverFilename = getFilenameFromContentDisposition(contentDisposition);

  const baseName = serverFilename || filenameFromList || `document_${documentId}`;
  const baseExt = extFromFilename(baseName);

  // Read first bytes for signature + debugging
  const head = await blobHeadBytes(blob, 128);

  console.log('📦 download debug:', {
    documentId,
    contentType,
    blobType: blob.type,
    bytes: blob.size,
    serverFilename,
    listFilename: filenameFromList,
    baseName,
    baseExt,
    headHex: toHex(head, 32),
    headAscii: toAsciiPreview(head, 80),
  });

  // 1) If it’s already valid binary for expected types, proceed
  const expectingPdf = baseExt === '.pdf' || String(contentType).toLowerCase().includes('pdf');
  const expectingDocx =
    baseExt === '.docx' ||
    String(contentType).toLowerCase().includes('officedocument.wordprocessingml');

  if (expectingPdf && isPdfBytes(head)) {
    const safeName = ensureExtension(baseName, contentType, '.pdf');
    return saveBlob(blob, safeName);
  }

  if (expectingDocx && isZipBytes(head)) {
    const safeName = ensureExtension(baseName, contentType, '.docx');
    return saveBlob(blob, safeName);
  }

  // 2) If not valid, check if it is BASE64 TEXT wrapped in a blob
  // (common when backend echoes base64 and sets blob content-type)
  const maybeText = await blobToText(blob);

  // Quick surface if it’s JSON/HTML (also common)
  const trimmed = maybeText.trim();
  if (trimmed.startsWith('{') || trimmed.startsWith('[') || trimmed.toLowerCase().includes('<html')) {
    throw new Error(
      `Backend did not return file bytes. It returned text (likely an error). ` +
        `Preview: ${trimmed.slice(0, 300)}`
    );
  }

  if (looksLikeBase64(maybeText)) {
    const bytes = base64ToBytes(maybeText);

    // Re-check signatures after decode
    const decodedHead = bytes.slice(0, 16);

    if (expectingPdf && isPdfBytes(decodedHead)) {
      const fixedBlob = new Blob([bytes], { type: 'application/pdf' });
      const safeName = ensureExtension(baseName, contentType, '.pdf');
      console.log('✅ decoded base64 -> PDF bytes');
      return saveBlob(fixedBlob, safeName);
    }

    if (expectingDocx && isZipBytes(decodedHead)) {
      const fixedBlob = new Blob([bytes], {
        type: 'application/vnd.openxmlformats-officedocument.wordprocessingml.document',
      });
      const safeName = ensureExtension(baseName, contentType, '.docx');
      console.log('✅ decoded base64 -> DOCX(zip) bytes');
      return saveBlob(fixedBlob, safeName);
    }

    // If it’s base64 but not what we expect, still fail with useful info
    throw new Error(
      `Downloaded blob looks like base64 text, but decoded bytes don't match expected file signature. ` +
        `Decoded head hex: ${toHex(decodedHead, 16)}`
    );
  }

  // 3) If it’s neither valid binary nor base64, it’s corrupted/truncated/mixed output.
  // Frontend cannot “repair” that; but we can throw a clear error.
  throw new Error(
    `Downloaded data is not a valid ${expectingPdf ? 'PDF' : expectingDocx ? 'DOCX' : 'file'}: ` +
      `signature mismatch. First bytes (hex): ${toHex(head, 16)} | ascii: ${toAsciiPreview(head, 60)}`
  );
}

function saveBlob(blob, filename) {
  const url = window.URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url;
  a.download = filename;
  document.body.appendChild(a);
  a.click();
  a.remove();
  window.URL.revokeObjectURL(url);
}
